1. import { joinSession } from "@github/copilot-sdk/extension";
2. import {
3.   MODEL_CANDIDATES,
4.   getModelFamily,
5.   normalizePrompt,
6.   includesAny,
7.   classifyPrompt,
8.   getTierCandidates,
9.   dedupeCandidates,
10.   orderCandidates,
11.   buildAdditionalContext,
12. } from "./policy.mjs";
13. 
14. // ---------------------------------------------------------------------------
15. // Session-level state
16. // ---------------------------------------------------------------------------
17. 
18. let lastImplementationModel = null;
19. let lastReviewModel = null;
20. let lastDecision = null;
21. 
22. // Confusion detection: tracks signs the agent may be stuck or looping.
23. // Err on the side of patience — especially when the agent is in active thinking
24. // (reasoning display enabled) — and only swap after multiple strong signals.
25. const confusionMetrics = {
26.   turnCount: 0,
27.   recentMessages: [], // last N agent messages for loop detection
28.   errorCount: 0,
29.   repeatedPatternCount: 0,
30.   lastSwitchTurn: -999, // turn when we last switched due to confusion
31.   currentModelFamily: null,
32. };
33. 
34. const CONFUSION_THRESHOLDS = {
35.   minTurnsSinceLastSwitch: 5,
36.   maxRecentMessagesTracked: 8,
37.   repeatingPatternThreshold: 3,
38.   consecutiveErrorThreshold: 2,
39.   similarityThreshold: 0.75,
40. };
41. 
42. // ---------------------------------------------------------------------------
43. // Confusion detection helpers (stateful — stay in this file)
44. // ---------------------------------------------------------------------------
45. 
46. function calculateSimilarity(text1, text2) {
47.   const words1 = new Set(
48.     normalizePrompt(text1)
49.       .split(/\s+/)
50.       .filter((w) => w.length > 3),
51.   );
52.   const words2 = new Set(
53.     normalizePrompt(text2)
54.       .split(/\s+/)
55.       .filter((w) => w.length > 3),
56.   );
57.   if (words1.size === 0 || words2.size === 0) return 0;
58.   const intersection = [...words1].filter((w) => words2.has(w)).length;
59.   const union = new Set([...words1, ...words2]).size;
60.   return union > 0 ? intersection / union : 0;
61. }
62. 
63. function detectConfusionSignals(message) {
64.   const text = normalizePrompt(message);
65.   const signals = [];
66. 
67.   const confusedPhrases = [
68.     "i'm not sure",
69.     "i'm confused",
70.     "unclear",
71.     "not clear",
72.     "i don't",
73.     "cannot proceed",
74.     "stuck",
75.     "unable to",
76.     "let me try",
77.     "let me re-attempt",
78.   ];
79.   if (includesAny(text, confusedPhrases)) signals.push("agent-confusion-acknowledgment");
80. 
81.   if (text.split(/\s+/).length < 10) signals.push("very-short-response");
82. 
83.   if (
84.     includesAny(text, ["can you", "could you", "would you", "please", "more details", "clarify"])
85.   ) {
86.     if ((text.match(/\?/g) || []).length > 2) signals.push("repetitive-asking");
87.   }
88. 
89.   if (text.includes("but earlier") || text.includes("wait,") || text.includes("i was wrong")) {
90.     signals.push("self-contradiction");
91.   }
92. 
93.   return signals;
94. }
95. 
96. function detectLoopingBehavior() {
97.   if (confusionMetrics.recentMessages.length < 3) return false;
98.   let similarPairs = 0;
99.   for (let i = confusionMetrics.recentMessages.length - 1; i > 0; i--) {
100.     if (
101.       calculateSimilarity(
102.         confusionMetrics.recentMessages[i],
103.         confusionMetrics.recentMessages[i - 1],
104.       ) > CONFUSION_THRESHOLDS.similarityThreshold
105.     ) {
106.       similarPairs++;
107.     }
108.   }
109.   return similarPairs >= 2;
110. }
111. 
112. async function getAlternateModel(session, currentModelId) {
113.   const currentFamily = getModelFamily(currentModelId);
114.   const targetFamily = currentFamily === "claude" ? "gpt" : "claude";
115. 
116.   let currentTier = null;
117.   for (const [tier, models] of Object.entries(MODEL_CANDIDATES)) {
118.     if (models.some((m) => m.id === currentModelId)) {
119.       currentTier = tier;
120.       break;
121.     }
122.   }
123.   if (!currentTier) return null;
124. 
125.   const tierCandidates = MODEL_CANDIDATES[currentTier] || [];
126.   const candidates = tierCandidates.filter((m) => getModelFamily(m.id) === targetFamily);
127. 
128.   // If tier exhausted in alternate family, try next tier up
129.   if (candidates.length === 0 && currentTier === "economy") {
130.     return (
131.       (MODEL_CANDIDATES.builder || []).find((m) => getModelFamily(m.id) === targetFamily) || null
132.     );
133.   }
134.   if (candidates.length === 0 && currentTier === "builder") {
135.     return (
136.       (MODEL_CANDIDATES.reasoning || []).find((m) => getModelFamily(m.id) === targetFamily) || null
137.     );
138.   }
139. 
140.   return candidates[0] || null;
141. }
142. 
143. async function considerConfusionSwap(session, currentModelId) {
144.   const turnsSinceSwitch = confusionMetrics.turnCount - confusionMetrics.lastSwitchTurn;
145.   if (turnsSinceSwitch < CONFUSION_THRESHOLDS.minTurnsSinceLastSwitch) return null;
146. 
147.   const isLooping = detectLoopingBehavior();
148.   const hasHighErrorRate =
149.     confusionMetrics.errorCount >= CONFUSION_THRESHOLDS.consecutiveErrorThreshold;
150. 
151.   // Only swap with solid evidence (looping + errors)
152.   if (!(isLooping && hasHighErrorRate)) return null;
153. 
154.   return getAlternateModel(session, currentModelId);
155. }
156. 
157. async function maybeSwapDueToConfusion(session, currentModelId) {
158.   const alternate = await considerConfusionSwap(session, currentModelId);
159.   if (!alternate) return null;
160. 
161.   try {
162.     await session.rpc.model.switchTo({
163.       modelId: alternate.id,
164.       reasoningEffort: alternate.reasoningEffort,
165.     });
166.     confusionMetrics.lastSwitchTurn = confusionMetrics.turnCount;
167.     confusionMetrics.errorCount = 0;
168.     await session.log(
169.       `model-router: Detected confusion/looping. Swapping from ${currentModelId} to ${alternate.id} (alternate family).`,
170.       { ephemeral: true },
171.     );
172.     return alternate;
173.   } catch {
174.     return null;
175.   }
176. }
177. 
178. // ---------------------------------------------------------------------------
179. // Model switching
180. // ---------------------------------------------------------------------------
181. 
182. async function trySwitchModel(session, route, currentModelId) {
183.   let candidates = orderCandidates(
184.     dedupeCandidates(getTierCandidates(route)),
185.     route,
186.     lastImplementationModel,
187.   );
188. 
189.   // For moderate-complexity builder tasks, try a same-model reasoning downgrade first
190.   if (
191.     (route.kind === "implementation" || route.kind === "general") &&
192.     route.tier === "builder" &&
193.     route.complexity <= 2 &&
194.     currentModelId
195.   ) {
196.     try {
197.       await session.rpc.model.switchTo({ modelId: currentModelId, reasoningEffort: "low" });
198.       return { id: currentModelId, reasoningEffort: "low" };
199.     } catch {
200.       // fall through to full model switching
201.     }
202.   }
203. 
204.   if (currentModelId) {
205.     candidates = candidates.filter((c) => c.id !== currentModelId);
206.   }
207. 
208.   // Review diversity: exclude last implementation model even when getCurrent() fails
209.   if (route.kind === "review" && lastImplementationModel) {
210.     candidates = candidates.filter((c) => c.id !== lastImplementationModel);
211.   }
212. 
213.   let selected = null;
214.   for (const candidate of candidates) {
215.     try {
216.       await session.rpc.model.switchTo({
217.         modelId: candidate.id,
218.         reasoningEffort: candidate.reasoningEffort,
219.       });
220.       selected = candidate;
221.       break;
222.     } catch {
223.       continue;
224.     }
225.   }
226. 
227.   return selected || { id: currentModelId || null, reasoningEffort: null };
228. }
229. 
230. // ---------------------------------------------------------------------------
231. // Session
232. // ---------------------------------------------------------------------------
233. 
234. const session = await joinSession({
235.   hooks: {
236.     onSessionStart: async () => {
237.       confusionMetrics.turnCount = 0;
238.       confusionMetrics.recentMessages = [];
239.       confusionMetrics.errorCount = 0;
240.       confusionMetrics.lastSwitchTurn = -999;
241.       await session.log("model-router loaded", { ephemeral: true });
242.       return {
243.         additionalContext:
244.           "The model-router extension is available. Favor the lowest-cost viable model and prefer a different model for review than implementation when possible.",
245.       };
246.     },
247. 
248.     onUserPromptSubmitted: async (input) => {
249.       confusionMetrics.turnCount++;
250.       const route = classifyPrompt(input.prompt);
251.       const current = await session.rpc.model.getCurrent().catch(() => ({ modelId: undefined }));
252.       const chosen = await trySwitchModel(session, route, current.modelId);
253. 
254.       if (route.kind === "implementation" || route.kind === "debugging") {
255.         lastImplementationModel = chosen.id || current.modelId || lastImplementationModel;
256.       }
257.       if (route.kind === "review") {
258.         lastReviewModel = chosen.id || current.modelId || lastReviewModel;
259.       }
260. 
261.       lastDecision = {
262.         kind: route.kind,
263.         complexity: route.complexity,
264.         selectedModelId: chosen.id || current.modelId || null,
265.         reasoningEffort: chosen.reasoningEffort || null,
266.       };
267. 
268.       await session.log(
269.         `model-router: ${route.kind} -> ${lastDecision.selectedModelId || "current model"}`,
270.         { ephemeral: true },
271.       );
272. 
273.       return {
274.         additionalContext: buildAdditionalContext(lastDecision, current.modelId, lastImplementationModel),
275.       };
276.     },
277. 
278.     onAgentMessage: async (message) => {
279.       const msgText = String(message.content || "");
280.       if (msgText.length > 0) {
281.         confusionMetrics.recentMessages.push(msgText);
282.         if (
283.           confusionMetrics.recentMessages.length > CONFUSION_THRESHOLDS.maxRecentMessagesTracked
284.         ) {
285.           confusionMetrics.recentMessages.shift();
286.         }
287.       }
288. 
289.       const signals = detectConfusionSignals(msgText);
290.       if (signals.length > 0) confusionMetrics.repeatedPatternCount++;
291. 
292.       const current = await session.rpc.model.getCurrent().catch(() => ({ modelId: undefined }));
293.       if (current.modelId) {
294.         const alternate = await maybeSwapDueToConfusion(session, current.modelId);
295.         if (alternate) confusionMetrics.currentModelFamily = getModelFamily(alternate.id);
296.       }
297.     },
298. 
299.     onError: async () => {
300.       confusionMetrics.errorCount++;
301.       if (confusionMetrics.errorCount >= CONFUSION_THRESHOLDS.consecutiveErrorThreshold) {
302.         const current = await session.rpc.model.getCurrent().catch(() => ({ modelId: undefined }));
303.         if (current.modelId) await maybeSwapDueToConfusion(session, current.modelId);
304.       }
305.     },
306.   },
307. 
308.   tools: [
309.     {
310.       name: "model_router_status",
311.       description:
312.         "Show the current model-router decision state and confusion metrics for this Copilot CLI session.",
313.       parameters: { type: "object", properties: {} },
314.       handler: async () => {
315.         const current = await session.rpc.model
316.           .getCurrent()
317.           .catch(() => ({ modelId: undefined }));
318.         const isLooping = detectLoopingBehavior();
319.         const turnsSinceLastSwitch =
320.           confusionMetrics.turnCount - confusionMetrics.lastSwitchTurn;
321.         return JSON.stringify(
322.           {
323.             // Quick-glance summary for local debugging
324.             debug: {
325.               activeModel: current.modelId || null,
326.               lastImplModel: lastImplementationModel,
327.               looping: isLooping,
328.               errorCount: confusionMetrics.errorCount,
329.               repeatedPatternCount: confusionMetrics.repeatedPatternCount,
330.               turnsSinceLastSwitch,
331.             },
332.             currentModel: current.modelId || null,
333.             lastImplementationModel,
334.             lastReviewModel,
